// Unwrap YC API response and normalize companies
const items = $input.all();
const companies = [];

for (const item of items) {
  const d = item.json;
  // YC API wraps results: { companies: [...], page, totalPages }
  const list = d.companies || [d];

  for (const company of list) {
    if (!company.website) continue;

    const domain = company.website
      .toLowerCase()
      .replace(/^https?:\/\//, '')
      .replace(/^www\./, '')
      .replace(/\/$/, '')
      .split('/')[0]
      .split('?')[0];

    if (!domain) continue;

    companies.push({
      company_name: company.name || '',
      website: domain,
      description: (company.one_liner || company.long_description || '').substring(0, 300),
      batch: company.batch || '',
      source: 'YC'
    });
  }
}

// Dedupe within this batch
const seen = new Set();
const unique = companies.filter(c => {
  if (seen.has(c.website)) return false;
  seen.add(c.website);
  return true;
});

console.log(`[Process YC] ${items.length} raw items → ${unique.length} unique companies`);
return [{ json: { companies: unique, total_scraped: unique.length } }];

// Compare scraped companies against existing sheet rows
const scrapedCompanies = $('Process YC Data').first().json.companies || [];

const existingDomains = new Set();
for (const item of $input.all()) {
  const raw = (item.json.website || item.json.Website || '').trim();
  if (!raw) continue;
  const domain = raw
    .toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/\/$/, '')
    .split('/')[0];
  if (domain) existingDomains.add(domain);
}

const newCompanies = scrapedCompanies.filter(c => !existingDomains.has(c.website));

console.log(`[Dedup] Scraped: ${scrapedCompanies.length} | In sheet: ${existingDomains.size} | New: ${newCompanies.length}`);

if (newCompanies.length === 0) return [];
return newCompanies.map(company => ({ json: company }));

// Merge Hunter results with company data
const hunterResp = $json;
const today = new Date().toISOString().split('T')[0];

const lead = {
  company_name: (hunterResp.company_name || hunterResp.data?.organization?.name || '').trim(),
  website:      (hunterResp.website || hunterResp.domain || hunterResp.data?.domain || '').trim(),
  source:       'YC',
  contact_name: '',
  contact_role: '',
  email:        '',
  batch:        hunterResp.batch || '',
  description:  (hunterResp.description || '').substring(0, 300),
  reply_status: 'queued',
  date_added:   today
};

// Pick best email by confidence
if (hunterResp.data?.emails?.length > 0) {
  const best = hunterResp.data.emails
    .filter(e => (e.confidence || 0) >= 50)
    .sort((a, b) => (b.confidence || 0) - (a.confidence || 0))[0];

  if (best) {
    lead.contact_name = (`${best.first_name || ''} ${best.last_name || ''}`).trim();
    lead.contact_role = best.position || best.seniority || '';
    lead.email        = best.value || '';
  }
}

console.log(`[Format Lead] ${lead.company_name} → ${lead.email || '(no email)'}`);
return { json: lead };
